async function githubRequest(path, options = {}) {
  const repository = requireEnv("GITHUB_REPOSITORY");
  const token = requireEnv("GITHUB_TOKEN");
  const url = new URL(`https://api.github.com/repos/${repository}${path}`);

  const response = await fetch(url, {
    ...options,
    headers: {
      accept: "application/vnd.github+json",
      authorization: `Bearer ${token}`,
      "content-type": "application/json",
      "x-github-api-version": "2022-11-28",
      ...(options.headers ?? {}),
    },
  });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(`GitHub API failed: ${response.status} ${body}`);
  }

  if (response.status === 204) {
    return null;
  }

  return response.json();
}

async function ensureLabel(name, color, description) {
  try {
    await githubRequest(`/labels/${encodeURIComponent(name)}`);
  } catch (error) {
    if (!String(error.message).includes("404")) {
      throw error;
    }

    await githubRequest("/labels", {
      method: "POST",
      body: JSON.stringify({ name, color, description }),
    });
  }
}

async function main() {
  const idea = pickIdea();
  const title = `[PDLC Research] ${idea.title}`;
  await ensureLabel("pdlc", "0E4A7B", "Product development lifecycle workflow");
  await ensureLabel("agent-workflow", "5319E7", "Issue handled by PDLC agents");
  await ensureLabel("research-proposal", "0E8A5F", "Generated by the research agent");

  const issue = await githubRequest("/issues", {
    method: "POST",
    body: JSON.stringify({
      title,
      body: renderIssueBody(idea),
      labels: ["pdlc", "agent-workflow", "research-proposal"],
    }),
  });

  console.log(`Created research issue #${issue.number}: ${issue.html_url}`);
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
